var val = Services.getValue(MonthlyInstallment.dataBinding);
var err = validateCurrencyValue(val, 999999.99 );
if( null == err)
{	Services.setValue(MonthlyInstallment.dataBinding, WPU.formatToTwoDP(val));
}
return err;

