function DefaultCurrency672() {}
DefaultCurrency672.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency672.tabIndex = -1;
DefaultCurrency672.maxLength = 1;
DefaultCurrency672.isReadOnly = function(){return true;}
DefaultCurrency672.isTemporary = function(){return true;}
DefaultCurrency672.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency672.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
